.spel-md .http-method.get{background:#61affe}.spel-md .http-method.post{background:#49cc90}.spel-md .http-method.put{background:#fca130}.spel-md .http-method.patch{background:#50e3c2}.spel-md .http-method.delete{background:#f93e3e}.spel-md .http-method.head{background:#9012fe}.spel-md .http-method.options{background:#0d5aa7}
