.spel-md .http-status.s2xx{background:#e6f9ee;color:#1a7f37}.spel-md .http-status.s3xx{background:#fff3cd;color:#856404}.spel-md .http-status.s4xx{background:#fce4e4;color:#c0392b}.spel-md .http-status.s5xx{background:#fce4e4;color:#c0392b}
