.spel-md .section-hdr{display:flex;align-items:center;gap:6px;margin:0 0 4px;font-size:.75em;font-weight:600;text-transform:uppercase;letter-spacing:.4px;color:var(--text-secondary,#888)}
.spel-md .code-wrap{position:relative;margin:4px 0 0}
