.spel-md .copy-btn{position:absolute;top:4px;right:4px;padding:3px 8px;border:1px solid var(--border-secondary,#ccc);border-radius:4px;background:var(--bg-control-secondary,#f5f5f5);color:var(--text-secondary,#666);font-size:.7em;cursor:pointer;font-family:var(--font-family,system-ui)}
