    curCard=type;
    out.push('<div class="http-card '+type+'">');
    out.push('<div class="card-hdr"><span class="card-icon">'+(cardIcon[type]||'')+'</span>'+cardTitle[type]+'</div>');
    out.push('<div class="card-body">');
